import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  homeContainer: {
    position: 'relative',
    zIndex: 0, // Set z-index to bring other elements above the image
  },
    hero: {
        display: 'flex',
        height: '100vh', // 100% of the viewport height
        overflow: 'hidden',
      },
      heroImageContainer: {
        position: 'fixed',
        top: 0,
        left: 0,
        width: '100%',
        height: '100vh',
        zIndex: -1, // Set z-index to make sure it's behind other elements
        overflow: 'hidden',
      },
      heroImage: {
        width: '100%',
        height: '100%',
        objectFit: 'cover',
      },
      heroContentContainer: {
        flex: '1',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        color: theme.palette.common.white,
      },
      heroContent: {
        textAlign: 'center',
      },
      heroWelcome: {
        fontSize: '2.5rem',
        fontWeight: 'bold',
        marginBottom: theme.spacing(2),
      },
      heroCTA: {
        color: theme.palette.common.white,
        backgroundColor: theme.palette.primary.main,
        '&:hover': {
          backgroundColor: theme.palette.primary.dark,
        },
      },
  featuredCollection: {
    // Featured collection styles
  },
  aboutCollector: {
    // About collector styles
  },
  collectionCategories: {
    // Collection categories styles
  },
  testimonials: {
    // Testimonials styles
  },
  newsletter: {
    // Newsletter styles
  },
  socialMedia: {
    // Social media styles
  },
  contact: {
    // Contact information styles
  },
}));

export default useStyles;
